function updateRollupAddress() external {
    if (msg.sender != IOwnable(rollup).owner())
        revert NotOwner(msg.sender, IOwnable(rollup).owner());
    IOwnable newRollup = bridge.rollup();
    if (rollup == newRollup) revert RollupNotChanged();
    rollup = newRollup;
}
